	return Step{
		ID:          StepID(id),
		Title:       title,
		Explanation: explanation,
	}
}

func (s *Step) SetCodeSnippet(snippet CodeSnippet) {
	s.CodeSnippet = &snippet
}

func (s *Step) SetDiagram(diagram Diagram) {
	s.Diagram = &diagram
}

